// Entrada: itens contendo JSON + binários (3 PDFs)
const inputItems = items;

// Função: normalizar nomes
function normalizeName(name) {
  return (name || "")
    .toLowerCase()
    .replace(/\.pdf$/i, "")
    .trim();
}

// Função: extrair filename do JSON
function findFileName(obj) {
  if (!obj) return null;
  const key = Object.keys(obj).find(k => /filename/i.test(k));
  if (key) {
    const v = obj[key];
    if (typeof v === 'string') return v.trim();
  }
  if (obj.binary) {
    const binKey = Object.keys(obj.binary)[0];
    if (binKey && obj.binary[binKey].fileName) return obj.binary[binKey].fileName.trim();
  }
  return null;
}

// Regex Data de Criação dd/mm/yyyy
function extractCreationDate(text) {
  if (!text || typeof text !== "string") return null;

  const patterns = [
    /Data de Criação\s*[:\-]?\s*(\d{2}\/\d{2}\/\d{4})/i,
    /Data de Criac(?:ã|a)o\s*[:\-]?\s*(\d{2}\/\d{2}\/\d{4})/i,
    /Data\s+de\s+Criação\s+(\d{2}\/\d{2}\/\d{4})/i,
    /Data\s+Cria(?:ç|c)[aã]o[:\s\-]*(\d{2}\/\d{2}\/\d{4})/i
  ];

  for (const rx of patterns) {
    const m = text.match(rx);
    if (m && m[1]) {
      const [d, mth, y] = m[1].split("/");
      const iso = `${y}-${mth}-${d}T00:00:00.000Z`;
      const dt = new Date(iso);
      if (!isNaN(dt)) return dt;
    }
  }
  return null;
}

// MONTANDO ARRAY ENRIQUECIDO
const pdfs = inputItems.map(it => {
  const p = it.json;
  return {
    raw: p,
    text: p.text || "",
    fileName: findFileName(p),
    creationDate: extractCreationDate(p.text),
    binary: it.binary || null
  };
});

// 1) Identificar pdf1
const pdf1 = pdfs.find(p =>
  p.text && p.text.toUpperCase().includes("DESPACHO DECISÓRIO")
);
if (!pdf1) throw new Error("Nenhum PDF contém 'DESPACHO DECISÓRIO'.");

// 2) Restantes → pdf2/pdf3
const remaining = pdfs.filter(p => p !== pdf1);

for (const r of remaining) {
  if (!r.creationDate) {
    throw new Error(
      `Não foi possível extrair 'Data de Criação' de ${r.fileName || "<sem nome>"}`
    );
  }
}

remaining.sort((a, b) => a.creationDate - b.creationDate);

const pdf2 = remaining[0];
const pdf3 = remaining[1];

// 3) MATCH EXATO DO BINÁRIO DO PDF1
const pdf1FileNorm = normalizeName(pdf1.fileName);
let pdf1BinaryMatch = null;

for (const it of inputItems) {
  if (!it.binary) continue;
  for (const bKey of Object.keys(it.binary)) {
    const bin = it.binary[bKey];
    const binNorm = normalizeName(bin.fileName || bKey);
    if (binNorm === pdf1FileNorm) {
      pdf1BinaryMatch = bin;
      break;
    }
  }
  if (pdf1BinaryMatch) break;
}

// 4) FORMATO DE SAÍDA
function fmtOut(p) {
  return {
    fileName: p.fileName,
    creationDate: p.creationDate ? p.creationDate.toISOString().split("T")[0] : null,
    numpages: p.raw.numpages,
    numrender: p.raw.numrender,
    text: p.text,                         // ← TEXTO COMPLETO AQUI
    textSnippet: (p.text || "").slice(0, 400)
  };
}

const out = {
  pdf1: fmtOut(pdf1),
  pdf2: fmtOut(pdf2),
  pdf3: fmtOut(pdf3),
  resolvedPdf1FileName: pdf1.fileName,
  debug: {
    expectedPdf1: pdf1.fileName,
    matchedBinaryFileName: pdf1BinaryMatch ? pdf1BinaryMatch.fileName : null
  }
};

// Saída n8n
return [
  {
    json: out,
    binary: pdf1BinaryMatch
      ? { pdf1: pdf1BinaryMatch }
      : {}
  }
];

async function main() {
  // 1. AGREGAÇÃO DE DADOS
  // Pega todos os itens que chegaram no input (não apenas o primeiro)
  const allItems = $input.all();

  let dadosUnificados = {};
  let arquivosDrive = [];

  // Percorre cada item recebido para juntar tudo em um lugar só
  for (const item of allItems) {
    const json = item.json;

    if (json.output) {
      // Se tem a chave "output", espalha o conteúdo dentro dos dados unificados
      // Isso vai juntar {cidade...} com {codigo_receita...} com {totais...}
      Object.assign(dadosUnificados, json.output);
    } else if (json.kind === 'drive#file') {
      // Se for um arquivo do Drive, guarda numa lista separada
      arquivosDrive.push(json);
    } else {
      // Caso sobre algo que não é output nem arquivo, joga no bolo principal
      Object.assign(dadosUnificados, json);
    }
  }

  // --- 1.5 LÓGICA DO VALOR ORIGINAL PERDCOMP 1 (NOVO TRECHO) ---
  let valorOriginalPerdcomp1 = null;
  const codigoFinal = dadosUnificados.codigo_receita_final;

  // Verifica qual código bate e pega o valor correspondente
  if (codigoFinal) {
    // Usamos .trim() para evitar erros caso venha com espaços extras
    const cod1 = dadosUnificados.codigo_da_receita_1;
    const cod2 = dadosUnificados.codigo_da_receita_2;
    const cod3 = dadosUnificados.codigo_da_receita_3;

    if (cod1 && codigoFinal.trim() === cod1.trim()) {
        valorOriginalPerdcomp1 = dadosUnificados.valor_original_credito_1;
    } else if (cod2 && codigoFinal.trim() === cod2.trim()) {
        valorOriginalPerdcomp1 = dadosUnificados.valor_original_credito_2;
    } else if (cod3 && codigoFinal.trim() === cod3.trim()) {
        valorOriginalPerdcomp1 = dadosUnificados.valor_original_credito_3;
    }
  }
  // -------------------------------------------------------------

  // Agora 'dadosUnificados' tem: cidade, data_ciencia, valores, códigos, etc.

  // 2. VALIDAÇÃO
  // Certifique-se de que data_ciencia existe nos dados unificados
  if (!dadosUnificados.data_ciencia) {
    // Se não achar a data, retorna os dados como chegaram sem calcular (evita erro fatal)
    return {
      ...dadosUnificados,
      arquivos_drive: arquivosDrive,
      erro: "Campo 'data_ciencia' não encontrado para cálculo."
    };
  }

  // 3. PREPARAÇÃO DA DATA
  const parts = dadosUnificados.data_ciencia.split("/");
  const dataCiencia = new Date(parts[2], parts[1] - 1, parts[0]);
  const ano = dataCiencia.getFullYear();

  // 4. FERIADOS (BrasilAPI)
  let feriadosNacionais = [];
  try {
    const feriados = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://brasilapi.com.br/api/feriados/v1/${ano}`,
      json: true
    });
    feriadosNacionais = feriados.map(f => f.date); 
  } catch (error) {
    feriadosNacionais = [
      `${ano}-01-01`, `${ano}-04-21`, `${ano}-05-01`,
      `${ano}-09-07`, `${ano}-10-12`, `${ano}-11-02`,
      `${ano}-11-15`, `${ano}-12-25`
    ];
  }

  // --- Funções auxiliares ---
  function isWeekend(date) {
    const day = date.getDay();
    return day === 0 || day === 6;
  }

  function isFeriado(date) {
    const dateStr = date.toISOString().split("T")[0];
    return feriadosNacionais.includes(dateStr);
  }

  function proximoDiaUtil(date) {
    let novaData = new Date(date);
    while (isWeekend(novaData) || isFeriado(novaData)) {
      novaData.setDate(novaData.getDate() + 1);
    }
    return novaData;
  }

  function formatDate(date) {
    const d = String(date.getDate()).padStart(2, "0");
    const m = String(date.getMonth() + 1).padStart(2, "0");
    const y = date.getFullYear();
    return `${d}/${m}/${y}`;
  }

  // 5. CÁLCULO DO PRAZO
  let dataInicio = new Date(dataCiencia);
  dataInicio.setDate(dataInicio.getDate() + 1); // Dia seguinte
  dataInicio = proximoDiaUtil(dataInicio);     // Próximo útil

  let dataFim = new Date(dataInicio);
  dataFim.setDate(dataFim.getDate() + 9);     // +10 dias contando o dia de inicio 
  dataFim = proximoDiaUtil(dataFim);           // Próximo útil se cair em feriado/fds

  // --- NOVA FUNÇÃO PARA FORMATAR "1 de dezembro de 2025" ---
function formatarDataPorExtenso(date) {
  const meses = [
    "janeiro", "fevereiro", "março", "abril", "maio", "junho",
    "julho", "agosto", "setembro", "outubro", "novembro", "dezembro"
  ];
  return `${date.getDate()} de ${meses[date.getMonth()]} de ${date.getFullYear()}`;
}

// Data de submissão = data atual
const dataSubmissao = new Date();

  // 6. RETORNO FINAL
  // Retorna tudo unificado + datas calculadas + arquivos do drive
  return {
    ...dadosUnificados, // Todos os campos de texto/valores juntos
    valor_original_perdcomp1: valorOriginalPerdcomp1,
    data_inicio_prazo: formatDate(dataInicio),
    data_fim_prazo: formatDate(dataFim),
    data_submissao: formatarDataPorExtenso(dataSubmissao),
    arquivos_anexos: arquivosDrive // Lista com os metadados dos arquivos (PDF/PNG)
  };
}

return main();

