={{
  (() => {
    const raw = $('Set Campos2').first().json.data_inicio_prazo;
    if (!raw) return null;

    // separa por / ou - automaticamente
    const parts = raw.includes('/') ? raw.split('/') : raw.split('-');

    // garante que sejam 3 partes (dia, mês, ano)
    if (parts.length !== 3) return null;

    // detecta se o formato é dd/mm/yyyy ou yyyy-mm-dd
    const isYearFirst = parts[0].length === 4;

    // monta o ISO (yyyy-mm-dd)
    const [day, month, year] = isYearFirst
      ? [parts[2], parts[1], parts[0]]
      : [parts[0], parts[1], parts[2]];

    // valida os números
    if (
      isNaN(Number(day)) ||
      isNaN(Number(month)) ||
      isNaN(Number(year))
    ) return null;

    return `${year.padStart(4, '0')}-${month.padStart(2, '0')}-${day.padStart(2, '0')}`;
  })()
}}

